import React, { useEffect, useRef } from 'react';

export interface LiquidRevealCardProps {
  /**
   * Card width in pixels
   * @default 380
   */
  width?: number;

  /**
   * Card height in pixels
   * @default 500
   */
  height?: number;

  /**
   * Main heading text
   */
  title: string;

  /**
   * Supporting description
   */
  description: string;

  /**
   * Additional container class names
   */
  className?: string;
}

/**
 * A tilting card with an interactive liquid-reveal spotlight.
 */
export const LiquidRevealCard: React.FC<LiquidRevealCardProps> = ({
  width = 380,
  height = 500,
  title,
  description,
  className = '',
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const cardRef = useRef<HTMLDivElement>(null);
  const liquidLayerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const container = containerRef.current;
    const card = cardRef.current;
    const liquidLayer = liquidLayerRef.current;
    if (!container || !card || !liquidLayer) return;

    // Tilt effect
    const handleMove = (e: MouseEvent) => {
      const rect = container.getBoundingClientRect();
      const dx = e.clientX - rect.left - rect.width / 2;
      const dy = e.clientY - rect.top - rect.height / 2;
      const rotateY = (dx / rect.width) * 15;
      const rotateX = (dy / rect.height) * -15;
      card.style.transform = `rotateY(${rotateY}deg) rotateX(${rotateX}deg)`;
    };
    const resetTilt = () => {
      card.style.transform = 'rotateY(0) rotateX(0)';
    };

    // Spotlight effect
    const handleLiquid = (e: MouseEvent) => {
      const rect = card.getBoundingClientRect();
      liquidLayer.style.setProperty('--mouse-x', `${e.clientX - rect.left}px`);
      liquidLayer.style.setProperty('--mouse-y', `${e.clientY - rect.top}px`);
    };

    container.addEventListener('mousemove', handleMove);
    container.addEventListener('mouseleave', resetTilt);
    card.addEventListener('mousemove', handleLiquid);

    return () => {
      container.removeEventListener('mousemove', handleMove);
      container.removeEventListener('mouseleave', resetTilt);
      card.removeEventListener('mousemove', handleLiquid);
    };
  }, []);

  return (
    <>
      {/* SVG filter (hidden from assistive tech) */}
      <svg className="absolute w-0 h-0" aria-hidden="true">
        <defs>
          <filter id="liquid-filter">
            <feTurbulence baseFrequency="0.01 0.03" numOctaves={3} seed={2} />
            <feDisplacementMap in="SourceGraphic" in2="turbulence" scale={50} />
          </filter>
        </defs>
      </svg>

      <div
        ref={containerRef}
        className={`card-container ${className}`}
        style={{ width, height }}
        role="region"
        aria-label={title}
        tabIndex={0}
        onFocus={() => cardRef.current?.classList.add('focus-within')}
        onBlur={() => cardRef.current?.classList.remove('focus-within')}
      >
        <div
          ref={cardRef}
          className="card flex flex-col justify-between p-8 text-foreground"
        >
          <div className="relative z-10">
            <h2 className="text-3xl font-bold">{title}</h2>
            <p className="mt-2 text-secondary">{description}</p>
          </div>

          <div ref={liquidLayerRef} className="liquid-layer" aria-hidden="true" />

          <div className="relative z-30 text-center">
            <h3 className="text-2xl font-semibold">Hover to Reveal</h3>
          </div>
        </div>
      </div>
    </>
  );
};

export default LiquidRevealCard;
